head.b:skin:
/* =====================================================
   PREMIUM BLOGGER THEME - Weight Loss Truth
   Design: Glassmorphism / Modern Minimal / Premium
   Font: Inter + Plus Jakarta Sans
   ===================================================== */

:root {
  --bg-primary: #0a0a0f;
  --bg-secondary: #12121a;
  --bg-card: #1a1a26;
  --bg-card-hover: #222230;
  --text-primary: #f1f1f7;
  --text-secondary: #a0a0b8;
  --text-muted: #6b6b80;
  --accent: #f97316;
  --accent-hover: #ea580c;
  --accent-light: rgba(249, 115, 22, 0.12);
  --accent-glow: rgba(249, 115, 22, 0.25);
  --border: #2a2a3a;
  --border-light: #333348;
  --success: #22c55e;
  --warning: #f59e0b;
  --danger: #ef4444;
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 24px;
  --shadow: 0 4px 24px rgba(0,0,0,0.3);
  --shadow-lg: 0 8px 48px rgba(0,0,0,0.4);
  --transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

/* ─── Reset ─── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; font-size: 16px; }
body {
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.7;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

/* ─── Scrollbar ─── */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: var(--bg-secondary); }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--text-muted); }

/* ─── Header / Navigation ─── */
#header-wrapper {
  position: fixed; top: 0; left: 0; right: 0; z-index: 1000;
  background: rgba(10, 10, 15, 0.85);
  backdrop-filter: blur(20px) saturate(1.5);
  -webkit-backdrop-filter: blur(20px) saturate(1.5);
  border-bottom: 1px solid var(--border);
  transition: var(--transition);
}
#header-wrapper.scrolled { background: rgba(10, 10, 15, 0.95); }
.header-inner {
  max-width: 1200px; margin: 0 auto;
  display: flex; align-items: center; justify-content: space-between;
  padding: 0 24px; height: 64px;
}
#logo h1, #logo h2 {
  font-family: 'Plus Jakarta Sans', sans-serif;
  font-size: 1.4rem; font-weight: 800;
  background: linear-gradient(135deg, var(--accent), #fbbf24);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  background-clip: text;
}
#logo a { text-decoration: none; color: inherit; }
.header-nav { display: flex; align-items: center; gap: 8px; }
.header-nav a {
  color: var(--text-secondary); text-decoration: none;
  font-size: 0.875rem; font-weight: 500;
  padding: 8px 16px; border-radius: var(--radius-sm);
  transition: var(--transition);
}
.header-nav a:hover { color: var(--text-primary); background: var(--accent-light); }
.search-toggle {
  background: var(--bg-card); border: 1px solid var(--border);
  color: var(--text-secondary); cursor: pointer;
  width: 40px; height: 40px; border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  transition: var(--transition); font-size: 1rem;
}
.search-toggle:hover { border-color: var(--accent); color: var(--accent); }

/* ─── Search Overlay ─── */
.search-overlay {
  position: fixed; top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(0,0,0,0.85); backdrop-filter: blur(12px);
  z-index: 2000; display: none; align-items: center; justify-content: center;
}
.search-overlay.active { display: flex; }
.search-overlay-inner { width: 100%; max-width: 600px; padding: 24px; }
.search-overlay input {
  width: 100%; padding: 20px 24px; font-size: 1.25rem;
  background: var(--bg-card); border: 1px solid var(--border);
  border-radius: var(--radius-md); color: var(--text-primary);
  outline: none; transition: var(--transition);
}
.search-overlay input:focus { border-color: var(--accent); }
.search-close {
  position: absolute; top: 24px; right: 24px;
  background: none; border: none; color: var(--text-secondary);
  font-size: 1.5rem; cursor: pointer; transition: var(--transition);
}
.search-close:hover { color: var(--text-primary); }

/* ─── Hero Banner ─── */
.hero-banner {
  margin-top: 64px; padding: 80px 24px 60px;
  background: linear-gradient(135deg, var(--bg-secondary) 0%, #1a1a2e 50%, var(--bg-primary) 100%);
  text-align: center; position: relative; overflow: hidden;
}
.hero-banner::before {
  content: ''; position: absolute; top: -50%; left: -50%;
  width: 200%; height: 200%;
  background: radial-gradient(circle at 30% 50%, var(--accent-light) 0%, transparent 50%),
              radial-gradient(circle at 70% 50%, rgba(59,130,246,0.08) 0%, transparent 50%);
  animation: heroGlow 8s ease-in-out infinite alternate;
}
@keyframes heroGlow {
  0% { transform: translate(0, 0); }
  100% { transform: translate(-5%, -5%); }
}
.hero-content { position: relative; z-index: 1; max-width: 800px; margin: 0 auto; }
.hero-banner h1 {
  font-family: 'Plus Jakarta Sans', sans-serif;
  font-size: clamp(2rem, 5vw, 3.5rem); font-weight: 800;
  line-height: 1.15; margin-bottom: 16px;
}
.hero-banner h1 span { background: linear-gradient(135deg, var(--accent), #fbbf24); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
.hero-banner p { font-size: 1.1rem; color: var(--text-secondary); max-width: 600px; margin: 0 auto 32px; line-height: 1.7; }
.hero-buttons { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; }
.hero-btn {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 14px 32px; border-radius: var(--radius-md);
  font-weight: 600; font-size: 0.95rem; text-decoration: none;
  transition: var(--transition); cursor: pointer; border: none;
}
.hero-btn-primary {
  background: linear-gradient(135deg, var(--accent), #ea580c);
  color: white; box-shadow: 0 4px 20px var(--accent-glow);
}
.hero-btn-primary:hover { transform: translateY(-2px); box-shadow: 0 8px 32px var(--accent-glow); }
.hero-btn-secondary {
  background: var(--bg-card); color: var(--text-primary);
  border: 1px solid var(--border);
}
.hero-btn-secondary:hover { border-color: var(--accent); transform: translateY(-2px); }

/* ─── Main Content ─── */
.main-wrapper {
  max-width: 1200px; margin: 0 auto; padding: 40px 24px;
  display: grid; grid-template-columns: 1fr 320px; gap: 48px;
}
@media (max-width: 968px) { .main-wrapper { grid-template-columns: 1fr; } }

/* ─── Blog Posts ─── */
.blog-posts { min-width: 0; }
.section-title {
  font-family: 'Plus Jakarta Sans', sans-serif;
  font-size: 1.5rem; font-weight: 700; margin-bottom: 24px;
  display: flex; align-items: center; gap: 12px;
}
.section-title::after {
  content: ''; flex: 1; height: 1px; background: linear-gradient(90deg, var(--border), transparent);
}
.post { margin-bottom: 32px; }
.post-outer { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-lg); overflow: hidden; transition: var(--transition); }
.post-outer:hover { border-color: var(--border-light); transform: translateY(-2px); box-shadow: var(--shadow); }
.post-thumbnail { width: 100%; height: 220px; object-fit: cover; display: block; }
.post-inner { padding: 24px; }
.post-category {
  display: inline-block; font-size: 0.75rem; font-weight: 600; text-transform: uppercase; letter-spacing: 0.05em;
  color: var(--accent); background: var(--accent-light); padding: 4px 12px; border-radius: 100px; margin-bottom: 12px;
}
.post-title {
  font-family: 'Plus Jakarta Sans', sans-serif;
  font-size: 1.35rem; font-weight: 700; line-height: 1.3; margin-bottom: 8px;
}
.post-title a { color: var(--text-primary); text-decoration: none; transition: var(--transition); }
.post-title a:hover { color: var(--accent); }
.post-meta {
  display: flex; align-items: center; gap: 16px;
  font-size: 0.8rem; color: var(--text-muted); margin-bottom: 12px;
  flex-wrap: wrap;
}
.post-meta span { display: flex; align-items: center; gap: 4px; }
.post-snippet { color: var(--text-secondary); font-size: 0.925rem; line-height: 1.7; }
.post-readmore {
  display: inline-flex; align-items: center; gap: 6px;
  margin-top: 16px; color: var(--accent); text-decoration: none;
  font-weight: 600; font-size: 0.875rem; transition: var(--transition);
}
.post-readmore:hover { gap: 10px; }

/* ─── Single Post Page ─── */
.post-body { font-size: 1.05rem; line-height: 1.8; color: var(--text-primary); }
.post-body h2 {
  font-family: 'Plus Jakarta Sans', sans-serif;
  font-size: 1.5rem; font-weight: 700; margin: 40px 0 16px; line-height: 1.3;
}
.post-body h3 {
  font-family: 'Plus Jakarta Sans', sans-serif;
  font-size: 1.2rem; font-weight: 600; margin: 32px 0 12px; line-height: 1.3;
}
.post-body p { margin-bottom: 16px; }
.post-body img {
  max-width: 100%; height: auto; border-radius: var(--radius-md);
  margin: 24px 0; box-shadow: var(--shadow);
}
.post-body blockquote {
  margin: 24px 0; padding: 20px 24px; background: var(--bg-secondary);
  border-left: 4px solid var(--accent); border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
  font-style: italic; color: var(--text-secondary); font-size: 1.05rem;
}
.post-body ul, .post-body ol { margin: 16px 0; padding-left: 24px; }
.post-body li { margin-bottom: 8px; }
.post-body table {
  width: 100%; border-collapse: collapse; margin: 24px 0;
  background: var(--bg-secondary); border-radius: var(--radius-md); overflow: hidden;
}
.post-body th, .post-body td { padding: 12px 16px; text-align: left; border-bottom: 1px solid var(--border); }
.post-body th { background: var(--bg-card); font-weight: 600; color: var(--accent); font-size: 0.875rem; text-transform: uppercase; letter-spacing: 0.03em; }
.post-body td { color: var(--text-secondary); font-size: 0.925rem; }
.post-body tr:last-child td { border-bottom: none; }
.post-body strong { color: var(--text-primary); }
.post-body a { color: var(--accent); text-decoration: underline; text-underline-offset: 2px; transition: var(--transition); }
.post-body a:hover { color: var(--accent-hover); }

/* ─── Callouts ─── */
.callout {
  margin: 24px 0; padding: 20px 24px; border-radius: var(--radius-md);
  display: flex; align-items: flex-start; gap: 12px;
}
.callout.success { background: rgba(34,197,94,0.08); border-left: 4px solid var(--success); color: #86efac; }
.callout.warning { background: rgba(245,158,11,0.08); border-left: 4px solid var(--warning); color: #fcd34d; }
.callout.info { background: rgba(59,130,246,0.08); border-left: 4px solid #3b82f6; color: #93c5fd; }

/* ─── TOC ─── */
.toc {
  background: var(--bg-secondary); border-radius: var(--radius-md);
  padding: 24px; margin-bottom: 32px; border: 1px solid var(--border);
}
.toc h3 { font-size: 1rem; font-weight: 700; margin-bottom: 12px; color: var(--accent); }
.toc ol { padding-left: 20px; }
.toc li { margin-bottom: 6px; font-size: 0.9rem; }
.toc a { color: var(--text-secondary); text-decoration: none; transition: var(--transition); }
.toc a:hover { color: var(--accent); }

/* ─── Sidebar ─── */
.sidebar { position: sticky; top: 88px; align-self: start; }
.sidebar-widget { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-lg); padding: 24px; margin-bottom: 24px; }
.sidebar-title {
  font-family: 'Plus Jakarta Sans', sans-serif;
  font-size: 1rem; font-weight: 700; margin-bottom: 16px;
  display: flex; align-items: center; gap: 8px;
}
.sidebar-title::before { content: ''; width: 3px; height: 18px; background: var(--accent); border-radius: 2px; }

/* ─── Newsletter ─── */
.newsletter-box { text-align: center; }
.newsletter-box h3 { font-size: 1.1rem; font-weight: 700; margin-bottom: 8px; }
.newsletter-box p { font-size: 0.85rem; color: var(--text-muted); margin-bottom: 16px; }
.newsletter-form { display: flex; gap: 8px; }
.newsletter-form input {
  flex: 1; padding: 12px 16px; background: var(--bg-primary);
  border: 1px solid var(--border); border-radius: var(--radius-sm);
  color: var(--text-primary); font-size: 0.9rem; outline: none;
  transition: var(--transition);
}
.newsletter-form input:focus { border-color: var(--accent); }
.newsletter-form button {
  padding: 12px 20px; background: var(--accent); color: white;
  border: none; border-radius: var(--radius-sm); font-weight: 600;
  font-size: 0.875rem; cursor: pointer; transition: var(--transition);
  white-space: nowrap;
}
.newsletter-form button:hover { background: var(--accent-hover); }

/* ─── Popular Posts ─── */
.popular-item { display: flex; gap: 12px; padding: 12px 0; border-bottom: 1px solid var(--border); }
.popular-item:last-child { border-bottom: none; }
.popular-item img { width: 64px; height: 64px; border-radius: var(--radius-sm); object-fit: cover; flex-shrink: 0; }
.popular-item h4 { font-size: 0.875rem; font-weight: 600; line-height: 1.3; margin-bottom: 4px; }
.popular-item h4 a { color: var(--text-primary); text-decoration: none; transition: var(--transition); }
.popular-item h4 a:hover { color: var(--accent); }
.popular-item .popular-date { font-size: 0.75rem; color: var(--text-muted); }

/* ─── Footer ─── */
#footer-wrapper {
  background: var(--bg-secondary); border-top: 1px solid var(--border);
  padding: 48px 24px 32px; margin-top: 48px;
}
.footer-inner { max-width: 1200px; margin: 0 auto; }
.footer-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 32px; margin-bottom: 32px; }
.footer-col h4 { font-size: 0.9rem; font-weight: 700; margin-bottom: 16px; color: var(--text-primary); }
.footer-col a { display: block; color: var(--text-muted); text-decoration: none; font-size: 0.85rem; padding: 4px 0; transition: var(--transition); }
.footer-col a:hover { color: var(--accent); }
.footer-bottom { padding-top: 24px; border-top: 1px solid var(--border); text-align: center; }
.footer-bottom p { font-size: 0.8rem; color: var(--text-muted); }
.social-links { display: flex; gap: 12px; margin-top: 12px; justify-content: center; }
.social-links a {
  width: 36px; height: 36px; border-radius: 50%;
  background: var(--bg-card); border: 1px solid var(--border);
  display: flex; align-items: center; justify-content: center;
  color: var(--text-muted); text-decoration: none; transition: var(--transition);
}
.social-links a:hover { border-color: var(--accent); color: var(--accent); transform: translateY(-2px); }

/* ─── Back to Top ─── */
.back-to-top {
  position: fixed; bottom: 24px; right: 24px; z-index: 999;
  width: 44px; height: 44px; border-radius: 50%;
  background: var(--accent); color: white; border: none;
  cursor: pointer; display: none; align-items: center; justify-content: center;
  box-shadow: 0 4px 16px var(--accent-glow); transition: var(--transition);
  font-size: 1.1rem;
}
.back-to-top.visible { display: flex; }
.back-to-top:hover { transform: translateY(-3px); box-shadow: 0 6px 24px var(--accent-glow); }

/* ─── Animations ─── */
.fade-in { opacity: 0; transform: translateY(20px); transition: opacity 0.6s ease, transform 0.6s ease; }
.fade-in.visible { opacity: 1; transform: translateY(0); }
@keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.7; } }

/* ─── Mobile ─── */
@media (max-width: 768px) {
  .header-inner { padding: 0 16px; }
  .header-nav { display: none; }
  .hero-banner { padding: 60px 16px 40px; }
  .hero-banner h1 { font-size: 1.75rem; }
  .main-wrapper { padding: 24px 16px; gap: 32px; }
  .sidebar { position: static; }
  .newsletter-form { flex-direction: column; }
  .post-thumbnail { height: 180px; }
  .blog-posts { order: 2; }
  .sidebar { order: 1; }
}

/* ─── Loading ─── */
.blog-loading {
  display: flex; align-items: center; justify-content: center;
  padding: 80px 24px; color: var(--text-muted);
}
.blog-loading .spinner {
  width: 32px; height: 32px; border: 3px solid var(--border);
  border-top-color: var(--accent); border-radius: 50%;
  animation: spin 0.8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

body.script:
// ─── Search Toggle ───
window.toggleSearch = function() {
  const overlay = document.getElementById('searchOverlay')
  overlay.classList.toggle('active')
  if (overlay.classList.contains('active')) {
    setTimeout(() => overlay.querySelector('input').focus(), 100)
  }
}

// ─── Header Scroll Effect ───
document.addEventListener('DOMContentLoaded', function() {
  const header = document.querySelector('#header-wrapper')
  const backToTop = document.getElementById('backToTop')

  window.addEventListener('scroll', function() {
    // Header
    if (window.scrollY > 20) {
      header.classList.add('scrolled')
    } else {
      header.classList.remove('scrolled')
    }

    // Back to top
    if (window.scrollY > 400) {
      backToTop.classList.add('visible')
    } else {
      backToTop.classList.remove('visible')
    }
  })

  // ─── Fade In Animation ───
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('visible')
      }
    })
  }, { threshold: 0.1 })

  document.querySelectorAll('.fade-in').forEach(el => observer.observe(el))

  // ─── Search Keyboard Shortcut ───
  document.addEventListener('keydown', function(e) {
    if (e.key === '/' && !e.ctrlKey && !e.metaKey && !['INPUT', 'TEXTAREA'].includes(e.target.tagName)) {
      e.preventDefault()
      window.toggleSearch()
    }
    if (e.key === 'Escape') {
      const overlay = document.getElementById('searchOverlay')
      if (overlay.classList.contains('active')) {
        window.toggleSearch()
      }
    }
  })
})
